import React, { createContext, useState, useContext, useEffect } from 'react';
import { api } from '../services/api';

const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
    const [user, setUser] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        // Al cargar la app, revisamos si hay una sesión activa en el navegador
        const savedSession = localStorage.getItem('user-session');
        if (savedSession) {
            setUser(JSON.parse(savedSession));
        }
        setLoading(false);
    }, []);

    const login = async (email, password) => {
        try {
            const data = await api.login(email, password);
            // data debe traer: { token, user: { id, nombre, rol, correo } }
            setUser(data);
            localStorage.setItem('user-session', JSON.stringify(data));
            return { success: true };
        } catch (error) {
            return { success: false, msg: error.message };
        }
    };

    const logout = () => {
        setUser(null);
        localStorage.removeItem('user-session');
        localStorage.removeItem('active-cart'); // Limpiamos carrito por seguridad
        window.location.href = '/login';
    };

    return (
        <AuthContext.Provider value={{ 
            user: user?.user, // El objeto del usuario
            token: user?.token, // El JWT para las cabeceras
            isAuthenticated: !!user,
            login, 
            logout,
            loading 
        }}>
            {!loading && children}
        </AuthContext.Provider>
    );
};

export const useAuth = () => useContext(AuthContext);
